import { z } from 'zod';

const dealSchema = z.object({
  title: z.string().min(1, 'Title is required'),
  value: z.number().optional(),
  status: z.string().optional(),
  company: z.string().optional(),
  contact_name: z.string().optional(),
  contact_email: z.string().email().optional(),
  notes: z.string().optional(),
  stage: z.string().optional()
});

const updateDealSchema = dealSchema.partial().extend({
  id: z.string().uuid('Invalid deal ID format')
});

// Example usage in POST endpoint
export async function POST(request: Request) {
  const supabase = createClient(
    process.env.SUPABASE_URL!,
    process.env.SUPABASE_KEY!
  );

  try {
    const dealData = dealSchema.parse(await request.json());

    const { data, error } = await supabase
      .from('pipeline_deals')
      .insert([dealData])
      .select();

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 });
    }

    return NextResponse.json(data[0], { status: 201 });
  } catch (err) {
    if (err instanceof z.ZodError) {
      return NextResponse.json({ error: err.errors }, { status: 400 });
    }
    return NextResponse.json({ error: 'Invalid request' }, { status: 400 });
  }
}
```

Implement a consistent error handling approach across all endpoints:

1. Create utility functions for standardized error responses
2. Add logging for errors and important operations
3. Ensure sensitive information is not exposed in error messages

```typescript
// Error handling utility
function handleError(error: any) {
  console.error('API Error:', error);

  // Determine if this is a client error or server error
  const isClientError = error.code === 'PGRST116' || error.message?.includes('validation');
  const status = isClientError ? 400 : 500;

  // Create safe error message
  const safeMessage = isClientError 
    ? error.message 
    : 'An unexpected error occurred';

  return NextResponse.json({ error: safeMessage }, { status });
}

